import{_ as e,o as a,c as r,a7 as i}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Materials","description":"","frontmatter":{},"headers":[],"relativePath":"en/items/materials.md","filePath":"en/items/materials.md","lastUpdated":1775394001000}'),d={name:"en/items/materials.md"};function l(s,t,n,o,h,m){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="materials" tabindex="-1">Materials <a class="header-anchor" href="#materials" aria-label="Permalink to &quot;Materials&quot;">​</a></h1><p>Materials are items used to level, ascend, and upgrade Awakeners, cards, and equipment in Morimens.</p><h2 id="awakener-exp-materials" tabindex="-1">Awakener EXP Materials <a class="header-anchor" href="#awakener-exp-materials" aria-label="Permalink to &quot;Awakener EXP Materials&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Material Name</th><th>Rarity</th><th>Source</th></tr></thead><tbody><tr><td>Gnosis Elixir I</td><td>Common (Green)</td><td>Resource Stages, Events, Dispatch. Overflow returns lowest-tier elixir; values below 500 round to 500.</td></tr><tr><td>Gnosis Elixir II</td><td>Rare (Blue)</td><td>Resource Stages, Events</td></tr><tr><td>Gnosis Elixir III</td><td>Epic (Purple)</td><td>Resource Stages, Events</td></tr><tr><td>Special Approval Elixir</td><td>High</td><td>Investigation chapter rewards (Ch.1 = 5, Ch.6 = 35)</td></tr></tbody></table><h2 id="awakener-ascension-materials" tabindex="-1">Awakener Ascension Materials <a class="header-anchor" href="#awakener-ascension-materials" aria-label="Permalink to &quot;Awakener Ascension Materials&quot;">​</a></h2><h3 id="ascension-caskets" tabindex="-1">Ascension Caskets <a class="header-anchor" href="#ascension-caskets" aria-label="Permalink to &quot;Ascension Caskets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Material Name</th><th>Rarity</th><th>Usage</th></tr></thead><tbody><tr><td>Basic Ascension Casket</td><td>Green</td><td>Initial ascension material (first breakthrough at Lv10). Realm-specific variants exist.</td></tr><tr><td>Intermediate Ascension Casket</td><td>Blue</td><td>Mid-level ascension material.</td></tr><tr><td>Advanced Ascension Casket</td><td>Purple</td><td>High-level ascension material.</td></tr></tbody></table><h3 id="domain-breakthrough-materials" tabindex="-1">Domain Breakthrough Materials <a class="header-anchor" href="#domain-breakthrough-materials" aria-label="Permalink to &quot;Domain Breakthrough Materials&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Material Name</th><th>Usage</th><th>Source</th></tr></thead><tbody><tr><td>Lucky Candy</td><td>Realm breakthrough material. Converts to 30 Mimetic Crystal on recall.</td><td>Realm-specific stages</td></tr><tr><td>Wax Figure Clay</td><td>Realm breakthrough material. Converts to 30 Mimetic Crystal on recall.</td><td>Realm-specific stages</td></tr><tr><td>Pitch-Black Clasp</td><td>Realm breakthrough material. Converts to 30 Mimetic Crystal on recall.</td><td>Realm-specific stages</td></tr><tr><td>Dimension Crystal</td><td>Realm breakthrough material. Converts to 30 Mimetic Crystal on recall.</td><td>Realm-specific stages</td></tr><tr><td>Devout Sacred Heart</td><td>Realm breakthrough material. Converts to 30 Mimetic Crystal on recall.</td><td>Realm-specific stages</td></tr><tr><td>Philosopher&#39;s Stone</td><td>Rare/universal breakthrough material.</td><td>Special sources</td></tr></tbody></table><h3 id="gnosis-advance-materials" tabindex="-1">Gnosis Advance Materials <a class="header-anchor" href="#gnosis-advance-materials" aria-label="Permalink to &quot;Gnosis Advance Materials&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Material Name</th><th>Usage</th><th>Source</th></tr></thead><tbody><tr><td>Primordial Spirit Core</td><td>Gnosis deepening (level cap 60 -&gt; 70). Each deepening requires 1 core + realm ascension material + Rose Scrip.</td><td>Sediment Shop (25 shards = 1 core, 3x/month)</td></tr><tr><td>Refined Primordial Spirit Core</td><td>Advanced gnosis deepening material.</td><td>Endgame content</td></tr><tr><td>Spirit Core Shard</td><td>Primordial Spirit Core fragment (25 = 1 core).</td><td>Temple exchange (2,000 temple coins = 10 shards)</td></tr><tr><td>Refined Spirit Core Shard</td><td>Advanced spirit core fragment.</td><td>Endgame content</td></tr></tbody></table><h2 id="skill-materials" tabindex="-1">Skill Materials <a class="header-anchor" href="#skill-materials" aria-label="Permalink to &quot;Skill Materials&quot;">​</a></h2><h3 id="skill-supplies" tabindex="-1">Skill Supplies <a class="header-anchor" href="#skill-supplies" aria-label="Permalink to &quot;Skill Supplies&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Material Name</th><th>Rarity</th><th>Source</th></tr></thead><tbody><tr><td>Basic Skill Supply</td><td>Green (unlocks at Lv25)</td><td>Dissolution Ruins</td></tr><tr><td>Intermediate Skill Supply</td><td>Blue</td><td>Dissolution Ruins</td></tr><tr><td>Advanced Skill Supply</td><td>Purple</td><td>Dissolution Ruins</td></tr></tbody></table><h3 id="domain-residues" tabindex="-1">Domain Residues <a class="header-anchor" href="#domain-residues" aria-label="Permalink to &quot;Domain Residues&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Material Name</th><th>Realm</th><th>Source</th></tr></thead><tbody><tr><td>Chaotic Residue</td><td><span class="realm-badge realm-chaos">Chaos</span></td><td>Chaos Dissolution Ruins / Chaos Settlement</td></tr><tr><td>Abyssal Residue</td><td><span class="realm-badge realm-aequor">Aequor</span></td><td>Aequor Dissolution Ruins / Ponape Ruins</td></tr><tr><td>Bloody Residue</td><td><span class="realm-badge realm-caro">Caro</span></td><td>Caro Dissolution Ruins / Worm Nest</td></tr><tr><td>Cosmic Residue</td><td><span class="realm-badge realm-ultra">Ultra</span></td><td>Ultra Dissolution Ruins / Schwarzschild&#39;s Throat</td></tr></tbody></table><h2 id="edification-materials" tabindex="-1">Edification Materials <a class="header-anchor" href="#edification-materials" aria-label="Permalink to &quot;Edification Materials&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Material Name</th><th>Rarity</th><th>Usage</th></tr></thead><tbody><tr><td>Pale Note</td><td>Green</td><td>Low-tier edification material. 3 = 1 Pale File.</td></tr><tr><td>Pale File</td><td>Blue</td><td>Mid-tier edification material. 3 = 1 Pale Tome.</td></tr><tr><td>Pale Tome</td><td>Purple</td><td>High-tier edification material.</td></tr><tr><td>Tempered Reason</td><td>—</td><td>Tempered series edification material.</td></tr><tr><td>Tempered Spirit</td><td>—</td><td>Advanced tempered series edification material.</td></tr><tr><td>Memory Replica</td><td>—</td><td>Memory-type trait edification material.</td></tr><tr><td>Emotion Replica</td><td>—</td><td>Emotion-type trait edification material.</td></tr><tr><td>Sentience Replica</td><td>—</td><td>Sentience-type trait edification material.</td></tr></tbody></table><h2 id="universal-materials" tabindex="-1">Universal Materials <a class="header-anchor" href="#universal-materials" aria-label="Permalink to &quot;Universal Materials&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Material Name</th><th>Usage</th><th>Source</th></tr></thead><tbody><tr><td>Mimetic Crystal</td><td>Universal synthesis resource. 30 = 1 Advanced Skill Supply. Breakthrough materials return at 30:1 on recall.</td><td>Curriculum advancement, Sediment/Deep Dive/Rose Scrip Shop</td></tr><tr><td>Memory Quill</td><td>Universal upgrade material (unlocks at Lv55). Up to 25-50 per week from 5 shops.</td><td>Sediment Shop, Deep Dive Shop, Investigation Shop, Lightless Shop, Phase Shop</td></tr><tr><td>Thousand-Face Seal</td><td>Covenant strengthening and transcription material. 36 seals to enhance a covenant from +0 to +12. Each transcription requires 3 seals + 7,500 Rose Scrip.</td><td>Various sources</td></tr></tbody></table><h2 id="remnant-dreams" tabindex="-1">Remnant Dreams <a class="header-anchor" href="#remnant-dreams" aria-label="Permalink to &quot;Remnant Dreams&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Material Name</th><th>Rarity</th><th>Source</th></tr></thead><tbody><tr><td>Shattered Remnant Dream</td><td>Common</td><td>D-Jewel Shop (100/week)</td></tr><tr><td>Stellar Remnant Dream</td><td>Rare</td><td>D-Jewel Shop (25/week)</td></tr></tbody></table><h2 id="enlightenment-materials" tabindex="-1">Enlightenment Materials <a class="header-anchor" href="#enlightenment-materials" aria-label="Permalink to &quot;Enlightenment Materials&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Material Name</th><th>Usage</th><th>Source</th></tr></thead><tbody><tr><td>Enlightenment Shard</td><td>Enlightenment system material for unlocking Awakener passive skills.</td><td>Duplicate summons</td></tr><tr><td>Soul Recall Core</td><td>Return currency when recalling limited Awakener enlightenment.</td><td>Enlightenment recall</td></tr><tr><td>Black Tribute</td><td>Universal resource material.</td><td>Gift boxes, events, investigation stages</td></tr></tbody></table><h2 id="alchemy-synthesis-system" tabindex="-1">Alchemy (Synthesis System) <a class="header-anchor" href="#alchemy-synthesis-system" aria-label="Permalink to &quot;Alchemy (Synthesis System)&quot;">​</a></h2><p>The alchemy system allows material synthesis:</p><ul><li>3 low-tier materials = 1 higher-tier material</li><li>30 Mimetic Crystal = 1 Advanced Skill Supply</li></ul><h2 id="level-recall" tabindex="-1">Level Recall <a class="header-anchor" href="#level-recall" aria-label="Permalink to &quot;Level Recall&quot;">​</a></h2><p>Resetting an Awakener&#39;s level, skills, and ascension returns <strong>all</strong> consumed materials in full. Breakthrough materials return as 30 Mimetic Crystal each.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Focus your material farming on whatever your main team needs most. See the <a href="./../awakeners/leveling.html">Leveling Guide</a> and <a href="./../cards/upgrade.html">Card Upgrades</a> for priority recommendations.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Items Overview</a></li><li><a href="./currency.html">Currency</a></li><li><a href="./../stages/resource.html">Resource Stages</a></li><li><a href="./../modes/smelting.html">Smelting Room</a></li><li><a href="./../awakeners/leveling.html">Leveling Guide</a></li></ul>',32)])])}const p=e(d,[["render",l]]);export{u as __pageData,p as default};
